/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel with:
 * - Phone number validation
 * - Message formatting from NotificationPayload
 * - Configurable SMS transport (injectable for testing)
 * - Retry-friendly error handling (never throws, returns success/failure)
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) currently
 * assumes email-only channels. It has `emailEnabled`, `emailFrequency`, and
 * per-category subscriptions scoped to email. To fully support SMS preferences,
 * the preferences model needs to be extended with:
 * - `smsEnabled: boolean` (master switch for SMS)
 * - Per-channel subscription settings (e.g., a channel-keyed structure instead
 *   of flat email-only fields)
 * - The `shouldSendEmail()` method in PreferencesService needs a channel-aware
 *   equivalent (e.g., `shouldSend(channel, userId, type)`)
 * - NotificationService.send() preference check (line ~124) is hardcoded to
 *   `payload.channel === 'email'` and needs to handle SMS too
 *
 * See decision 01KN8GQESP159Q7NKWBNCM5Y8J for the original email-only design.
 */

import type { NotificationAdapter, AdapterSendResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A recorded SMS for inspection in tests and debugging.
 */
export interface SentSms {
  to: string;
  message: string;
  sentAt: Date;
}

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  /** Sender ID or phone number shown as the sender */
  fromNumber: string;
  /** Maximum message length before truncation */
  maxMessageLength: number;
}

/**
 * Transport interface for actually sending SMS messages.
 * Inject a real implementation (Twilio, AWS SNS, etc.) in production,
 * or use the default in-memory transport for testing.
 */
export interface SmsTransport {
  sendSms(options: {
    from: string;
    to: string;
    message: string;
  }): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport that records SMS messages instead of sending them.
 * Used in development and testing.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: SentSms[] = [];
  private nextId = 1;

  async sendSms(options: {
    from: string;
    to: string;
    message: string;
  }): Promise<{ messageId: string }> {
    this.sent.push({
      to: options.to,
      message: options.message,
      sentAt: new Date(),
    });
    return { messageId: `sms-${String(this.nextId++).padStart(4, '0')}` };
  }

  getSentMessages(): SentSms[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
    this.nextId = 1;
  }
}

/**
 * Phone number validation regex.
 * Accepts formats: +1234567890, +44 20 7946 0958, (555) 123-4567, etc.
 * Must contain at least 7 digits.
 */
const PHONE_REGEX = /^\+?[\d\s\-().]{7,}$/;

const defaultConfig: SmsAdapterConfig = {
  fromNumber: '+1-555-000-0000',
  maxMessageLength: 160,
};

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private config: SmsAdapterConfig;
  private transport: SmsTransport;

  constructor(config?: Partial<SmsAdapterConfig>, transport?: SmsTransport) {
    this.config = { ...defaultConfig, ...config };
    this.transport = transport ?? new InMemorySmsTransport();
  }

  async send(payload: NotificationPayload): Promise<AdapterSendResult> {
    // Validate recipient phone number
    if (!this.isValidPhoneNumber(payload.recipient)) {
      this.logger.warn(`Invalid phone number: ${payload.recipient}`);
      return {
        success: false,
        error: `Invalid phone number: ${payload.recipient}`,
      };
    }

    // Format the SMS message
    const message = this.formatMessage(payload);

    // Send via transport
    try {
      const result = await this.transport.sendSms({
        from: this.config.fromNumber,
        to: payload.recipient,
        message,
      });

      this.logger.info(`SMS sent to ${payload.recipient} (${result.messageId})`);

      return {
        success: true,
        providerResponse: { messageId: result.messageId },
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return {
        success: false,
        error: message,
      };
    }
  }

  /**
   * Format the notification payload into an SMS message.
   * Combines subject and body, truncating to maxMessageLength.
   */
  formatMessage(payload: NotificationPayload): string {
    const full = `${payload.subject}: ${payload.body}`;
    if (full.length <= this.config.maxMessageLength) {
      return full;
    }
    return full.substring(0, this.config.maxMessageLength - 3) + '...';
  }

  /**
   * Validate a phone number format.
   */
  isValidPhoneNumber(phone: string): boolean {
    return PHONE_REGEX.test(phone);
  }

  /**
   * Get all SMS messages sent through this adapter (only works with InMemorySmsTransport).
   */
  getSentMessages(): SentSms[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getSentMessages();
    }
    return [];
  }

  /**
   * Clear recorded SMS messages (only works with InMemorySmsTransport).
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }
}

