import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type { SmsTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+1-555-123-4567',
    subject: 'Order Update',
    body: 'Your order has shipped.',
    channel: 'sms',
    type: 'order-status-update',
    priority: 'normal',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter(undefined, transport);
  });

  describe('send', () => {
    it('should send an SMS successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerResponse?.messageId).toBe('sms-0001');
    });

    it('should record messages via InMemorySmsTransport', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+1-555-123-4567');
      expect(sent[0]?.message).toContain('Order Update');
    });

    it('should reject invalid phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-phone' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject empty phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should handle transport errors without throwing', async () => {
      const failingTransport: SmsTransport = {
        async sendSms() {
          throw new Error('SMS gateway unavailable');
        },
      };
      const failAdapter = new SmsAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
    });

    it('should handle non-Error transport exceptions', async () => {
      const failingTransport: SmsTransport = {
        async sendSms() {
          throw 'string error';
        },
      };
      const failAdapter = new SmsAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown transport error');
    });

    it('should return sequential message IDs', async () => {
      const r1 = await adapter.send(makePayload());
      const r2 = await adapter.send(makePayload({ recipient: '+44 20 7946 0958' }));

      expect(r1.providerResponse?.messageId).toBe('sms-0001');
      expect(r2.providerResponse?.messageId).toBe('sms-0002');
    });
  });

  describe('phone number validation', () => {
    it.each([
      '+1-555-123-4567',
      '+442079460958',
      '+44 20 7946 0958',
      '(555) 123-4567',
      '5551234567',
      '+1 (555) 123-4567',
    ])('should accept valid phone number: %s', (phone) => {
      expect(adapter.isValidPhoneNumber(phone)).toBe(true);
    });

    it.each([
      '',
      'abc',
      '123',
      'phone',
      '+1-abc',
    ])('should reject invalid phone number: "%s"', (phone) => {
      expect(adapter.isValidPhoneNumber(phone)).toBe(false);
    });
  });

  describe('message formatting', () => {
    it('should combine subject and body', () => {
      const message = adapter.formatMessage(makePayload());
      expect(message).toBe('Order Update: Your order has shipped.');
    });

    it('should truncate long messages to maxMessageLength', () => {
      const longBody = 'A'.repeat(200);
      const message = adapter.formatMessage(makePayload({ body: longBody }));

      expect(message.length).toBe(160);
      expect(message.endsWith('...')).toBe(true);
    });

    it('should not truncate messages within limit', () => {
      const message = adapter.formatMessage(makePayload({
        subject: 'Hi',
        body: 'Short',
      }));
      expect(message).toBe('Hi: Short');
    });

    it('should respect custom maxMessageLength', () => {
      const customAdapter = new SmsAdapter({ maxMessageLength: 50 }, transport);
      const message = customAdapter.formatMessage(makePayload({
        subject: 'Subject',
        body: 'A very long body that exceeds the fifty character limit for this test',
      }));

      expect(message.length).toBe(50);
      expect(message.endsWith('...')).toBe(true);
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', async () => {
      await adapter.send(makePayload());

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
    });

    it('should use custom from number', async () => {
      const customTransport: SmsTransport = {
        lastFrom: '',
        async sendSms(options) {
          (this as any).lastFrom = options.from;
          return { messageId: 'test-1' };
        },
      } as any;

      const customAdapter = new SmsAdapter(
        { fromNumber: '+1-800-CUSTOM' },
        customTransport,
      );
      await customAdapter.send(makePayload());

      expect((customTransport as any).lastFrom).toBe('+1-800-CUSTOM');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentMessages()).toEqual([]);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toEqual([]);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customAdapter = new SmsAdapter(undefined, {
        async sendSms() {
          return { messageId: '1' };
        },
      });
      expect(customAdapter.getSentMessages()).toEqual([]);
    });
  });

  describe('channel property', () => {
    it('should be sms', () => {
      expect(adapter.channel).toBe('sms');
    });
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should record sent messages', async () => {
    await transport.sendSms({
      from: '+1-555-000-0000',
      to: '+1-555-123-4567',
      message: 'Hello',
    });

    const sent = transport.getSentMessages();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('+1-555-123-4567');
    expect(sent[0]?.message).toBe('Hello');
  });

  it('should clear all messages', async () => {
    await transport.sendSms({
      from: '+1-555-000-0000',
      to: '+1-555-123-4567',
      message: 'Hello',
    });
    transport.clear();
    expect(transport.getSentMessages()).toEqual([]);
  });

  it('should generate sequential message IDs', async () => {
    const r1 = await transport.sendSms({
      from: '+1-555-000-0000', to: '+1-555-123-4567', message: 'A',
    });
    const r2 = await transport.sendSms({
      from: '+1-555-000-0000', to: '+1-555-123-4567', message: 'B',
    });

    expect(r1.messageId).toBe('sms-0001');
    expect(r2.messageId).toBe('sms-0002');
  });

  it('should reset IDs on clear', async () => {
    await transport.sendSms({
      from: '+1-555-000-0000', to: '+1-555-123-4567', message: 'A',
    });
    transport.clear();
    const r = await transport.sendSms({
      from: '+1-555-000-0000', to: '+1-555-123-4567', message: 'B',
    });
    expect(r.messageId).toBe('sms-0001');
  });
});

